mapper.select:
SELECT A.* FROM ( SELECT 0 as member_group_idx, 'CMS' AS site_id, 'CMS' AS member_group_name, -1 AS parent_member_group_idx, 0 AS member_group_depth, '' AS remark, 0 AS print_seq, 'Y' AS default_group_yn, 'N' AS admin_yn, 'N' AS admin_group_yn, 'N' AS user_group_yn, 'N' AS guest_group_yn FROM DUAL UNION ALL SELECT member_group_idx, site_id, member_group_name, parent_member_group_idx, member_group_depth, remark, print_seq, default_group_yn, admin_yn, admin_group_yn, user_group_yn, guest_group_yn FROM WB_MEMBER_GROUP a WHERE guest_group_yn = 'N'
AND site_id = #{site_id}
) A CONNECT BY PRIOR member_group_idx = parent_member_group_idx START WITH parent_member_group_idx = -1 ORDER SIBLINGS BY CASE WHEN site_id = 'CMS' THEN site_id END ASC, CASE WHEN site_id != 'CMS' THEN TO_NUMBER(SUBSTR(site_id,2)) END ASC, print_seq

mapper.insert:
INSERT INTO
	WB_MEMBER_GROUP_RELATION
(
	member_group_idx, relation_member_group_idx
)
	VALUES
(
	#{member_group_idx}, #{relation_member_group_idx}
)

mapper.select:
SELECT LISTAGG(NVL(z.homepage_name, 'CMS') || ':' || A.member_group_name, ', ') WITHIN GROUP (ORDER BY A.parent_member_group_idx, A.member_group_idx) AS RESULT FROM WB_MEMBER_GROUP A LEFT JOIN CMS_HOMEPAGE Z ON Z.homepage_id = A.site_id WHERE A.member_group_idx IN
#{member_group_idx}
ORDER BY A.parent_member_group_idx, A.member_group_idx
